#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int countWays(char **grid, int n, int x, int y) {
    if (x == n) return 1;
    if (y == n) return countWays(grid, n, x + 1, 0);
    if (grid[x][y] != '?') return countWays(grid, n, x, y + 1);

    int count = 0;
    char orig = grid[x][y];
    for (char c = 'B'; c <= 'P'; c++) {
        if (c == 'G') {
            if (x > 0 && grid[x - 1][y] != '.') return count;
            if (x < n - 1 && grid[x + 1][y] != '.') return count;
            if (y > 0 && grid[x][y - 1] != '.') return count;
            if (y < n - 1 && grid[x][y + 1] != '.') return count;
        } else if (c == 'B') {
            if (x > 0 && grid[x - 1][y] == 'P') return count;
            if (x > 0 && grid[x - 1][y] == 'G') return count;
            if (x < n - 1 && grid[x + 1][y] == 'P') return count;
            if (x < n - 1 && grid[x + 1][y] == 'G') return count;
            if (y > 0 && grid[x][y - 1] == 'P') return count;
            if (y > 0 && grid[x][y - 1] == 'G') return count;
            if (y < n - 1 && grid[x][y + 1] == 'P') return count;
            if (y < n - 1 && grid[x][y + 1] == 'G') return count;
        } else if (c == 'P') {
            if (x > 0 && grid[x - 1][y] == 'B') return count;
            if (x > 0 && grid[x - 1][y] == 'G') return count;
            if (x < n - 1 && grid[x + 1][y] == 'B') return count;
            if (x < n - 1 && grid[x + 1][y] == 'G') return count;
            if (y > 0 && grid[x][y - 1] == 'B') return count;
            if (y > 0 && grid[x][y - 1] == 'G') return count;
            if (y < n - 1 && grid[x][y + 1] == 'B') return count;
            if (y < n - 1 && grid[x][y + 1] == 'G') return count;
        }
        grid[x][y] = c;
        count += countWays(grid, n, x, y + 1);
        count %= MOD;
        grid[x][y] = orig;
    }
    return count;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        char **grid = (char **)malloc(n * sizeof(char *));
        for (int i = 0; i < n; i++) {
            grid[i] = (char *)malloc((n + 1) * sizeof(char));
            scanf("%s", grid[i]);
        }
        printf("%d\n", countWays(grid, n, 0, 0));
        for (int i = 0; i < n; i++) free(grid[i]);
        free(grid);
    }
    return 0;
}

